import React, { useState, useEffect } from "react";
import { loadService } from "../services";
import LoadCard from "../components/LoadCard";
import "../styles/LoadList.css";

const LoadList = () => {
  const [loads, setLoads] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [filters, setFilters] = useState({
    status: "",
    search: "",
    pickupLocation: "",
    dropLocation: "",
    page: 1,
  });
  const [pagination, setPagination] = useState({
    total: 0,
    pages: 1,
    currentPage: 1,
  });

  useEffect(() => {
    fetchLoads();
  }, [filters]);

  const fetchLoads = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await loadService.getLoads(filters);
      setLoads(response.loads);
      setPagination(response.pagination);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to fetch loads");
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters((prev) => ({
      ...prev,
      [name]: value,
      page: 1,
    }));
  };

  const handleClearFilters = () => {
    setFilters({
      status: "",
      search: "",
      pickupLocation: "",
      dropLocation: "",
      page: 1,
    });
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this load?")) {
      try {
        await loadService.deleteLoad(id);
        setLoads(loads.filter((load) => load.id !== id));
      } catch (err) {
        setError(err.response?.data?.message || "Failed to delete load");
      }
    }
  };

  const handlePageChange = (newPage) => {
    setFilters((prev) => ({
      ...prev,
      page: newPage,
    }));
  };

  return (
    <div className="load-list-container">
      {/* Sidebar Filter */}
      <div className={`filter-sidebar ${sidebarOpen ? "open" : "closed"}`}>
        <div className="sidebar-header">
          <h3>🔍 Filters</h3>
          <button
            className="sidebar-toggle"
            onClick={() => setSidebarOpen(!sidebarOpen)}
            title={sidebarOpen ? "Close sidebar" : "Open sidebar"}
          >
            {sidebarOpen ? "✕" : "☰"}
          </button>
        </div>

        <div className="filter-groups">
          {/* Search Filter */}
          <div className="filter-group">
            <label htmlFor="search">Search Loads</label>
            <input
              id="search"
              type="text"
              name="search"
              placeholder="Enter title or description..."
              value={filters.search}
              onChange={handleFilterChange}
              className="filter-input"
            />
          </div>

          {/* Pickup Location Filter */}
          <div className="filter-group">
            <label htmlFor="pickupLocation">📍 Pickup Location</label>
            <input
              id="pickupLocation"
              type="text"
              name="pickupLocation"
              placeholder="e.g., New York, aruppukottai"
              value={filters.pickupLocation}
              onChange={handleFilterChange}
              className="filter-input"
            />
          </div>

          {/* Drop Location Filter */}
          <div className="filter-group">
            <label htmlFor="dropLocation">📍 Drop Location</label>
            <input
              id="dropLocation"
              type="text"
              name="dropLocation"
              placeholder="e.g., Los Angeles, kariapatti"
              value={filters.dropLocation}
              onChange={handleFilterChange}
              className="filter-input"
            />
          </div>

          {/* Status Filter */}
          <div className="filter-group">
            <label htmlFor="status">Status</label>
            <select
              id="status"
              name="status"
              value={filters.status}
              onChange={handleFilterChange}
              className="filter-select"
            >
              <option value="">All Status</option>
              <option value="Pending">Pending</option>
              <option value="Booked">Booked</option>
              <option value="Completed">Completed</option>
            </select>
          </div>

          {/* Clear Filters Button */}
          <button className="btn-clear-filters" onClick={handleClearFilters}>
            Clear All Filters
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="load-content">
        {error && <div className="error-message">{error}</div>}

        {loading ? (
          <div className="loading">Loading loads...</div>
        ) : (
          <>
            {loads.length === 0 ? (
              <div className="no-loads">
                <p>No loads found</p>
                <small>Try adjusting your filters</small>
              </div>
            ) : (
              <>
                <div className="loads-header">
                  <p className="loads-count">Found {pagination.total} loads</p>
                </div>
                <div className="loads-grid">
                  {loads.map((load) => (
                    <LoadCard
                      key={load.id}
                      load={load}
                      onDelete={handleDelete}
                    />
                  ))}
                </div>
              </>
            )}

            {pagination.pages > 1 && (
              <div className="pagination">
                <button
                  onClick={() =>
                    handlePageChange(pagination.currentPage - 1)
                  }
                  disabled={pagination.currentPage === 1}
                >
                  ← Previous
                </button>
                <span>
                  Page {pagination.currentPage} of {pagination.pages}
                </span>
                <button
                  onClick={() =>
                    handlePageChange(pagination.currentPage + 1)
                  }
                  disabled={pagination.currentPage === pagination.pages}
                >
                  Next →
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default LoadList;
